#include <stdio.h>

void insertion_sort(int arr[], int n) {
    for (int i = 1; i < n; ++i) {
        int key = arr[i];
        int j = i - 1;
        while (j >= 0 && arr[j] > key) {
            arr[j + 1] = arr[j];
            --j;
        }
        arr[j + 1] = key;
    }
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n;
        scanf("%d", &n);
        int arr[1000]; // N <= 1000
        for (int i = 0; i < n; ++i) {
            scanf("%d", &arr[i]);
        }
        insertion_sort(arr, n);
        for (int i = 0; i < n; ++i) {
            printf("%d", arr[i]);
            if (i + 1 < n) printf(" ");
        }
        printf("\n");
    }
    return 0;
}

